#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M, K;
        scanf("%d %d %d", &N, &M, &K);
        int diff = N - M;
        if (diff < 0) diff = -diff;
        if (diff > K) printf("%d\n", diff);
        else printf("%d\n", diff % 2);
    }
    return 0;
}

