import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int M = sc.nextInt();
            int K = sc.nextInt();
            int diff = N - M;
            if (diff < 0) diff = -diff;
            if (diff > K) System.out.println(diff);
            else System.out.println(diff % 2);
        }
    }
}

